                        "path": "filteredExpenses[]",
                        "value": "$expense"
                      }
                    }
                  ]
                }
              }
            ]
          }
        },
        {
          "compute": {
            "expression": "sum($filteredExpenses, 'amount')",
            "into": "totalAmount"
          }
        },
