                          {
                            "compute": {
                              "expression": "if($categorySum, $categorySum + $exp.amount, $exp.amount)",
                              "into": "categorySum"
                            }
                          }
                        ]
                      }
                    }
                  ]
                }
              },
              {
                "branch": {
                  "condition": "$categorySum > 0",
